const items = $input.all();

// Agrupa todos os dados históricos
const historico = items.map(i => ({
  data: i.json.data_conversa,
  total_conversas: parseInt(i.json.total_conversas) || 0,
  total_convertidas: parseInt(i.json.total_convertidas) || 0,
  valor_total: parseFloat(i.json.valor_total_dia) || 0
}));

const totalDias = historico.length;
const somaValores = historico.reduce((acc, d) => acc + d.valor_total, 0);
const mediadiaria = totalDias > 0 ? somaValores / totalDias : 0;
const maxDia = Math.max(...historico.map(d => d.valor_total));
const minDia = Math.min(...historico.map(d => d.valor_total));
const taxaConversao = historico.reduce((acc, d) => acc + (d.total_convertidas / Math.max(d.total_conversas, 1)), 0) / Math.max(totalDias, 1);

// Data de início da previsão (amanhã)
const hoje = new Date();
const amanha = new Date(hoje);
amanha.setDate(amanha.getDate() + 1);
const emSeteDias = new Date(hoje);
emSeteDias.setDate(emSeteDias.getDate() + 7);

const prompt = `Você é um especialista em previsão financeira e fluxo de caixa. Com base nos dados históricos dos últimos ${totalDias} dias, gere uma previsão de caixa para os próximos 7 dias.

Dados históricos resumidos:
- Média diária de receita: R$ ${mediadiaria.toFixed(2)}
- Máximo diário: R$ ${maxDia.toFixed(2)}
- Mínimo diário: R$ ${minDia.toFixed(2)}
- Taxa de conversão média: ${(taxaConversao * 100).toFixed(1)}%
- Total de dias analisados: ${totalDias}

Histórico detalhado (últimos ${Math.min(totalDias, 10)} dias):
${JSON.stringify(historico.slice(0, 10), null, 2)}

Gere previsões para 3 cenários. Retorne APENAS um JSON válido com esta estrutura:
{
  "otimista": {
    "confianca_modelo": 0.75,
    "previsao_diaria": [
      {"data": "YYYY-MM-DD", "valor_previsto": 1500.00, "conversoes_previstas": 5}
    ],
    "gaps_detectados": [
      {"tipo": "gap identificado", "data": "YYYY-MM-DD", "impacto": "descrição"}
    ]
  },
  "realista": {
    "confianca_modelo": 0.85,
    "previsao_diaria": [
      {"data": "YYYY-MM-DD", "valor_previsto": 1000.00, "conversoes_previstas": 3}
    ],
    "gaps_detectados": []
  },
  "pessimista": {
    "confianca_modelo": 0.70,
    "previsao_diaria": [
      {"data": "YYYY-MM-DD", "valor_previsto": 600.00, "conversoes_previstas": 2}
    ],
    "gaps_detectados": [
      {"tipo": "risco identificado", "data": "YYYY-MM-DD", "impacto": "descrição"}
    ]
  }
}

As datas devem ser os próximos 7 dias a partir de ${amanha.toISOString().split('T')[0]}. Não inclua markdown, apenas o JSON puro.`;

// Retorna um único item com todos os dados consolidados
return [{
  json: {
    historico,
    totalDias,
    mediadiaria,
    periodo_inicio: amanha.toISOString().split('T')[0],
    periodo_fim: emSeteDias.toISOString().split('T')[0],
    prompt
  }
}];

const response = $input.first().json;
const content = response.content?.[0]?.text || '{}';
let parsed;
try { parsed = JSON.parse(content); } catch(e) { parsed = {erro: 'parse_failed', raw: content}; }

const baseData = $input.first().json;
const cenarios = ['otimista', 'realista', 'pessimista'];

// Se houve erro no parse, retorna um item com erro
if (parsed.erro) {
  return [{json: {...baseData, resultado: parsed, cenario: null}}];
}

// Retorna 3 itens, um por cenário
return cenarios.map(cenario => ({
  json: {
    ...baseData,
    resultado: parsed,
    cenario,
    dados_cenario: parsed[cenario] || {}
  }
}));
